class Person:
    def __init__(self, name):
        self.name = name

class Manager(Person):
    def __init__(self, name, team_size):
        super().__init__(name) # Call parent constructor
        self.team_size = team_size

    def manage(self):
        return f"{self.name} is managing a team of {self.team_size}."

